(window.webpackJsonp=window.webpackJsonp||[]).push([[192],{819:function(n,r){n.exports="\x3c!-- \ntitle: 02-第二节课\nsort: \n--\x3e \n\n> 上一节内容的扩展\n\n- [ ] 我为什么使用Linux?\n- [ ] 如何记笔记?\n- [ ] 基础Linux命令\n  - 文件管理\n  - 权限\n- [ ] vim操作技巧\n\n## 为什么使用Linux\n\n> 让同学们对Linux感兴趣\n>\n> 演示使用manjaro+i3wm\n\n### Win10\n\n> 糟糕窗口管理\n>\n> 系统比Linux大几十倍\n>\n> 但开发者常用工具并不内置\n>\n> 安装软件糟糕的体验(下一步..下一步..下一步)\n\n### Linux\n\n> 快捷窗口管理\n>\n> 安装软件只需一行命令,并且不用考虑放在c盘还是d盘.\n>\n> 无须到处翻找乱七八糟的应用\n\n## 如何记笔记\n\n> 参考我这篇\n\n## Linux基础命令\n\n- `ls`\n\n  > -a: 显示隐藏文件\n  >\n  > -l: 长格式列出信息\n  >\n  > `ls | grep test`\n\n  ```bash\n  ls -l\n  drwxr-xr-x   4 fzf fzf   4096 11月 20 10:53 C\n  # 一个目录\n  drwxr-xr-x\t[文件类型 d目录] [权限->用户|组|其他] \n  4 fzf fzf\t[内部文件数] [所属用户] [所属组] \n  4096 11月 20 10:53 C\t[文件大小 目录皆为4096] [修改时间] [文件名]\n  \n  -rwxrwxr-x  1 fzf  fzf      194 11月 16 17:07 demo.c\n  # 一个文件020-03-10 16\n  -rwxrwxr-x\t[文件类型 -文件] [权限->用户|组|其他] \n  4 fzf fzf\t[链接数] [所属用户] [所属组] \n  4096 11月 20 10:53 C\t[文件大小 目录皆为4096] [修改时间] [文件名]\n  ```\n\n- `cd`\n\n  > change dir\t切换目录\n\n- `mkdir <dir1> <dir2>...`\n\n  > 新建目录\n\n- `cat`\n\n  > 把文件内容打印到标准输出\n\n- `mv`\n\n  > 移动文件 {or 改名}\n\n- `rm`\n\n  > 删除文件\n  >\n  > -r: 递归删除\n  >\n  > -f: 强制删除\n\n- `cp`\n\n  > 复制\n  >\n  > 参数说明同上\n\n- `chmod`\n\n  > 设置权限\n  >\n  > `chmod u/g/o -/+ r/w/x  [file]`\n  >\n  > u/g/o: 用户 组 其他\n  >\n  > -/+: 去掉/增加权限\n  >\n  > r/w/x: 读/写/运行\n  >\n  > `chmod u+w demo`: 为demo所属用户+w权限\n  >\n  > 775下回讲\n\n## Vim\n\n| 命令                     | 功能                                                   |\n| ------------------------ | ------------------------------------------------------ |\n| y<br />[number] yy       | 复制<br />复制n行                                      |\n| p                        | 粘贴                                                   |\n| iI/aA/oO                 | 插入+行首/当前字符+末尾/下一行+上一行                  |\n| c<br />ciw<br />cf[char] | change<br />修改当前光标下的word<br />修改到第一个char |\n\n "}}]);